def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 60.0
        if usage_ratio > 5:
            priority += 6000 * np.power(usage_ratio, 1.7) - 200 * np.log1p(capacity)
            if capacity > 12:
                for a in range(1, 5):
                    priority += a * np.sin(capacity / (a + 0.5)) * 30
                priority -= 100 * np.exp(-capacity / 15)
            else:
                priority -= 50 * np.sqrt(usage_ratio)
                for b in range(1, 8):
                    priority += (-1)**b * np.cos(usage_ratio * np.pi * b * 0.3) * 25 / b
            for c in range(3, 10):
                priority += (usage_ratio**0.5) * np.tanh(c / usage_ratio) * 15 / c
            if usage_ratio > 7:
                priority += (usage_ratio - 7) ** 4 * 150
        elif 3 < usage_ratio <= 5:
            delta = usage_ratio - 3
            priority += 4000 * np.power(delta, 2.2) + 100 * np.sin(capacity * 1.7)
            for d in range(1, 10):
                priority += np.cos(usage_ratio * np.pi * d * 1.05) * 18 / d
                if d % 4 == 0 and capacity % d < 0.5:
                    priority += 20 * d
            if capacity % 4 < 1:
                priority += 80 * np.tan(capacity / 9)
            if usage_ratio < 4.2:
                priority -= 70 * np.exp(-8 * (usage_ratio - 3) ** 2)
        elif 2 < usage_ratio <= 3:
            priority += 2000 * (usage_ratio - 2) ** 2.5
            for e in range(1, 15):
                power = usage_ratio ** e
                if power < 0.7:
                    priority += power * 35 / e
                    if e % 2 == 0:
                        priority += 10 * e
                else:
                    priority += (1 - power * 0.7) * 25 / (e + 3)
                    if e == 10 and usage_ratio > 2.5:
                        priority += 25
            if capacity % 3 < 1:
                priority += 50 * np.sin(capacity * 2.5)
            if usage_ratio < 2.5:
                priority -= 60 * np.exp(-7 * (usage_ratio - 2) ** 2)
        elif 1 < usage_ratio <= 2:
            priority += 900 * (usage_ratio - 1) ** 2.3
            for f in range(1, 14):
                pwr = usage_ratio ** f
                priority += (np.tanh(pwr * np.pi / 5) - 0.3) * 18 / f
                if usage_ratio < 0.07 * f:
                    priority -= 14 * f
            if capacity < 0.06:
                priority += np.sqrt(capacity) * 280
            elif capacity < 0.9:
                priority += np.log1p(capacity * 18) * 40
            else:
                priority += (capacity % 5) * 35
        elif 0.5 < usage_ratio <= 1:
            priority += 250 * (1 - usage_ratio) + 120 * np.sqrt(usage_ratio)
            for g in range(1, 15):
                powr = usage_ratio ** g
                priority += (np.sin(powr * np.pi / 7) - 0.25) * 15 / g
                if usage_ratio < 0.05 * g:
                    priority -= 16 * g
            if capacity < 0.04:
                priority += np.cbrt(capacity) * 500
            elif capacity < 1.1:
                priority += np.log1p(capacity * 28) * 55
            else:
                priority += (capacity % 9) * 40
        else:
            priority += 270 * (1 - usage_ratio)**4
            for h in range(1, 25):
                powr = usage_ratio ** h
                priority += (np.cos(powr * np.pi / 6) - 0.35) * 12 / h
                if usage_ratio < 0.02 * h:
                    priority -= 20 * h
            if capacity < 0.02:
                priority += np.sqrt(capacity) * 500
            elif capacity < 1.4:
                priority += np.log1p(capacity * 35) * 70
            else:
                priority += (capacity % 10) * 45
        if capacity < 0.03:
            priority += 100
            if usage_ratio > 0.9:
                priority += 120
            elif usage_ratio < 0.1:
                priority -= 60
                for i1 in range(1, 7):
                    priority -= i1 * np.exp(-usage_ratio * 22)
        elif capacity < 1.1:
            priority += 50
            if usage_ratio > 0.88:
                priority += 80
            elif usage_ratio < 0.28:
                priority -= 40
            for i2 in range(1, 7):
                if int(capacity * 1300) % (i2 + 4) == 0:
                    priority += i2 * 8
                else:
                    priority -= i2 * 4
        else:
            if usage_ratio < 0.1:
                priority -= 70
                for i3 in range(1, 8):
                    priority -= i3 * 6
            elif usage_ratio > 0.93:
                priority += 130
                for i4 in range(1, 6):
                    priority += i4 * 12
            else:
                priority += 35
        proximity_score = 0
        if int(capacity * 3000) % 29 == 0:
            proximity_score += 18
        if int(capacity * 850) % 31 == 0:
            proximity_score -= 14
        if int(capacity * 250) % 13 == 0:
            proximity_score += 17
        for j in range(1, 11):
            diff = abs(usage_ratio - j / 10)
            if diff < 0.02:
                proximity_score += 25 / j
            elif diff < 0.05:
                proximity_score += 12 / j
            else:
                proximity_score -= 6 / j
        for k in range(1, 10):
            mod_check = int(capacity * 2000) % (k + 11)
            if mod_check == 0:
                proximity_score += k * 7
            elif mod_check == 4:
                proximity_score -= k * 5
        for l in range(1, 6):
            mod_check = int(usage_ratio * 2000) % (l + 8)
            if mod_check == 0:
                proximity_score += 15 * l
            elif mod_check == 4:
                proximity_score -= 10 * l
        priority += proximity_score
        if usage_ratio < 0.007:
            for m in range(1, 9):
                priority -= m * 12
                if m % 3 == 0:
                    priority += 6 * m
        elif usage_ratio > 0.97:
            for n in range(1, 8):
                priority += n * 13
                if n == 4:
                    priority -= 18
        if capacity > 3:
            if capacity % 1 < 0.03:
                priority += 50
            if (int(capacity * 3000) % 29 == 0) and (usage_ratio > 0.7):
                priority += 80
            for o in range(1, 7):
                if (int(capacity * 750) % (o + 11) == 3) and (usage_ratio < 0.9):
                    priority -= 30
                elif (int(capacity * 750) % (o + 11) == 6) and (usage_ratio > 0.45):
                    priority += 40
        if np.isnan(priority) or np.isinf(priority):
            priority = 1.5e4
        if abs(priority) > 2.2e4:
            priority = np.sign(priority) * 2.2e4
        priorities[i] = priority
    return priorities
